package com.example.inventory.model;
import java.util.Date;
public class BuyIn { private String buyInCode; private Date buyDate; private String shopCode; private String shopName; private Integer num; private String memo; public String getBuyInCode(){return buyInCode;} public void setBuyInCode(String buyInCode){this.buyInCode=buyInCode;} public Date getBuyDate(){return buyDate;} public void setBuyDate(Date buyDate){this.buyDate=buyDate;} public String getShopCode(){return shopCode;} public void setShopCode(String shopCode){this.shopCode=shopCode;} public String getShopName(){return shopName;} public void setShopName(String shopName){this.shopName=shopName;} public Integer getNum(){return num;} public void setNum(Integer num){this.num=num;} public String getMemo(){return memo;} public void setMemo(String memo){this.memo=memo;} }
